# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient
import json

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['cms']
users_collection = db['users']
documents_collection = db['documents']

@app.route('/register', methods=['POST'])
def register():
    user_data = request.json
    users_collection.insert_one(user_data)
    return jsonify({'message': 'User registered successfully'})

@app.route('/get_user_profile', methods=['GET'])
def get_user_profile():
    username = request.args.get('username')
    user_data = users_collection.find_one({'username': username})
    if user_data:
        return jsonify(user_data)
    else:
        return jsonify({'error': 'User not found'}), 404

@app.route('/add_document', methods=['POST'])
def add_document():
    document_data = request.json
    documents_collection.insert_one(document_data)
    return jsonify({'message': 'Document added successfully'})

@app.route('/get_documents', methods=['GET'])
def get_documents():
    query_params = request.args.to_dict()
    cursor = documents_collection.find(query_params)
    documents_list = list(cursor)
    return jsonify(documents_list)

@app.route('/aggregate_documents', methods=['GET'])
def aggregate_documents():
    pipeline = [
        {'$match': request.args.to_dict()},
        {'$group': {'_id': None, 'total_views': {'$sum': '$views'}}}
    ]
    result = documents_collection.aggregate(pipeline)
    return jsonify(list(result))

if __name__ == '__main__':
    app.run(debug=True)